func countPartitions(nums []int, k int) int {
	const mod int = 1e9 + 7
	sl := redblacktree.New[int, int]()
	merge := func(st *redblacktree.Tree[int, int], x, v int) {
		c, _ := st.Get(x)
		if c+v == 0 {
			st.Remove(x)
		} else {
			st.Put(x, c+v)
		}
	}
	n := len(nums)
	f := make([]int, n+1)
	g := make([]int, n+1)
	f[0], g[0] = 1, 1
	for l, r := 1, 1; r <= n; r++ {
		merge(sl, nums[r-1], 1)
		for sl.Right().Key-sl.Left().Key > k {
			merge(sl, nums[l-1], -1)
			l++
		}
		f[r] = g[r-1]
		if l >= 2 {
			f[r] = (f[r] - g[l-2] + mod) % mod
		}
		g[r] = (g[r-1] + f[r]) % mod
	}
	return f[n]
}

